INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (923, 0, 0, 115711, 1, "フードコートで売っているのであれば\n何ら違和感はないけれど。", 10, 0.5, 11, 19230021, 0);
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (923, "", "", 0, "", "", "", "", 91, 19230022, "");
